nodes.description:
async function ensureOakLogs(bot, count = 4) {
    // The function ensures the bot acquires at least a specified number (default 4) of oak logs by first verifying surface accessibility, attempting vertical or downward exploration if needed, and then mining oak logs directly or through repeated exploration and mining cycles until the target count is met.
}

nodes.code:
async function ensureOakLogs(bot, count = 4) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  function isReachableSurface() {
    if (!bot.entity) return false;

    // First priority: check for oak_log blocks at or near current Y level (±3)
    const nearbyLogs = bot.findBlocks({
      matching: mcData.blocksByName["oak_log"].id,
      maxDistance: 32,
      count: 10,
    });

    if (nearbyLogs.length > 0) {
      for (const pos of nearbyLogs) {
        const logBlock = bot.blockAt(pos);
        if (logBlock && Math.abs(logBlock.position.y - bot.entity.position.y) <= 3) {
          return true;
        }
      }
    }

    // Fallback: check if bot is within 10 blocks of surface (y ≥ surface_y - 10)
    const surfaceY = bot.map.getHeight(bot.entity.position.x, bot.entity.position.z);
    if (bot.entity.position.y >= surfaceY - 10) return true;

    // Additional fallback: check for underground oak logs (e.g., from jungle temples or deep caves)
    // Search for oak_log at any Y level up to maxDistance (48 to be safe)
    const undergroundLogs = bot.findBlocks({
      matching: mcData.blocksByName["oak_log"].id,
      maxDistance: 48,
      count: 1,
    });
    if (undergroundLogs.length > 0) return true;

    return false;
  }

  function logDebug(msg) {
    bot.chat(`[ensureOakLogs] ${msg}`);
  }

  // Pre-flight: verify surface accessibility
  if (!isReachableSurface()) {
    logDebug("Surface not accessible — attempting vertical ascent to reach surface level");

    // Primary fallback: attempt to ascend vertically using exploreUntil
    try {
      const ascended = await exploreUntil(bot, new Vec3(0, 1, 0), 60, () => {
        return isReachableSurface() ? true : null;
      });

      if (ascended) {
        logDebug("Ascended successfully; now checking for oak logs again.");
        if (!isReachableSurface()) {
          throw new Error("Surface still not accessible after vertical ascent");
        }
      } else {
        logDebug("Vertical ascent failed; attempting underground exploration for oak logs");

        // Try exploring downward to find underground oak logs (e.g., from caves or structures)
        const downExploration = await exploreUntil(bot, new Vec3(0, -1, 0), 60, () => {
          return isReachableSurface() ? true : null;
        });

        if (downExploration) {
          logDebug("Exploration downward succeeded; now checking for oak logs.");
        } else {
          logDebug("Downward exploration also failed — attempting direct underground search for oak logs");
          const underground = bot.findBlocks({
            matching: mcData.blocksByName["oak_log"].id,
            maxDistance: 48,
            count: 1,
          });
          if (underground.length === 0) {
            throw new Error("No oak logs found — ascent and underground exploration both failed");
          }
        }
      }
    } catch (e) {
      logDebug(`Error during fallback: ${e.message}`);
      throw new Error(`Surface not accessible — fallback failed: ${e.message}`);
    }
  }

  logDebug("Surface accessible or underground oak logs found, proceeding to mine oak_log");

  // Check if already have enough in inventory
  const existing = bot.inventory.findInventoryItem(mcData.itemsByName["oak_log"].id);
  if (existing && existing.count >= count) {
    logDebug(`Already have ${existing.count} oak_log in inventory.`);
    return existing.count;
  }

  const maxDistance = 32;

  // Pre-check: look for oak logs within range before attempting to mine
  const initialCheck = bot.findBlocks({
    matching: mcData.blocksByName["oak_log"].id,
    maxDistance: maxDistance,
    count: 1,
  });

  if (initialCheck.length === 0) {
    logDebug("No oak_log nearby, trying to explore...");

    // Explore to find oak logs
    const found = await exploreUntil(bot, new Vec3(1, 0, 1), 60, () => {
      const nearby = bot.findBlocks({
        matching: mcData.blocksByName["oak_log"].id,
        maxDistance: maxDistance,
        count: 1,
      });
      return nearby.length > 0 ? true : null;
    });

    if (!found) {
      throw new Error("No oak logs found nearby after exploration");
    }
  }

  // Mine oak logs directly
  const mined = await mineBlock(bot, "oak_log", count);
  if (mined >= count) {
    logDebug(`Successfully mined ${mined} oak logs.`);
    return mined;
  }

  logDebug(`Only mined ${mined} oak logs, trying to find more.`);

  // Try exploring again if not enough logs found
  const additionalFound = await exploreUntil(bot, new Vec3(1, 0, 1), 60, () => {
    const nearby = bot.findBlocks({
      matching: mcData.blocksByName["oak_log"].id,
      maxDistance: maxDistance,
      count: 1,
    });
    return nearby.length > 0 ? true : null;
  });

  if (!additionalFound) {
    throw new Error("No additional oak logs found after second exploration attempt");
  }

  const additional = await mineBlock(bot, "oak_log", count - mined);
  logDebug(`Mined additional ${additional} logs.`);

  const total = mined + additional;
  if (total < count) {
    throw new Error(`Insufficient oak logs: mined ${total} of ${count} required`);
  }

  return total;
}

nodes.description:
async function craftOakCraftingTable(bot) {
    // The function crafts a crafting table from oak planks. First, it checks if the bot is underground and verifies if at least 4 oak planks are in inventory. If not, it checks for oak logs and crafts enough planks (1 log yields 4 planks) to reach the needed 4. Then, it crafts a crafting table using a 2×2 recipe with 4 planks. After crafting, it confirms the table is in inventory, places it using an external skill, and verifies the placement by finding the placed crafting table block nearby.
}

nodes.code:
async function craftOakCraftingTable(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Environment adaptation: Check if underground (y < 58) to avoid unnecessary log mining
  if (bot.entity.position.y < 58) {
    bot.chat("Underground — checking inventory for planks before mining logs...");
  }

  // Verify we have at least 4 oak_planks (NOT logs) required for crafting table
  const oakPlanks = bot.inventory.findInventoryItem(mcData.itemsByName["oak_planks"].id);

  // Calculate how many planks we need to craft
  const planksNeeded = 4;
  const currentPlanks = oakPlanks ? oakPlanks.count : 0;
  const planksToCraft = Math.max(0, planksNeeded - currentPlanks);

  // If we don't have enough planks, we need to craft them from logs
  if (planksToCraft > 0) {
    // First ensure we have logs if needed
    const oakLogs = bot.inventory.findInventoryItem(mcData.itemsByName["oak_logs"].id);
    if (!oakLogs || oakLogs.count < 1) {
      bot.chat(
        "Insufficient materials to craft oak_planks. Need at least 1 oak_log, have: " + (oakLogs ? oakLogs.count : 0),
      );
      return;
    }

    // Craft planks: 1 log makes 4 planks, so craft enough to meet need
    const logCraftsNeeded = Math.ceil(planksToCraft / 4);
    await craftItem(bot, "oak_planks", logCraftsNeeded);
  }

  // Verify we now have at least 4 oak_planks
  const finalPlanks = bot.inventory.findInventoryItem(mcData.itemsByName["oak_planks"].id);
  if (!finalPlanks || finalPlanks.count < 4) {
    bot.chat("Insufficient oak_planks to craft crafting table. Need 4, have: " + (finalPlanks ? finalPlanks.count : 0));
    return;
  }

  // Step: Craft 1 crafting table from 4 oak planks (2x2 recipe)
  await craftItem(bot, "crafting_table", 1);

  // Verify crafting success: check if crafting table is in inventory
  const craftingTable = bot.inventory.findInventoryItem(mcData.itemsByName["crafting_table"].id);
  if (!craftingTable || craftingTable.count < 1) {
    bot.chat(
      "Failed to craft crafting table. Current inventory: " +
        JSON.stringify(
          bot.inventory.items().map((i) => ({
            name: i.name,
            count: i.count,
          })),
        ),
    );
    return;
  }

  bot.chat("Crafted 1 crafting table successfully!");

  // Place the crafting table using the external skill (which handles safe positioning)
  await placeCraftingTable(bot);

  // LAYER 1 FIX: Use findBlock to confirm *any* crafting table block exists nearby
  const placedTable = bot.findBlock({
    matching: mcData.blocksByName.crafting_table.id,
    maxDistance: 32,
  });
  if (!placedTable) {
    throw new Error("Crafting table not found in world after placement");
  }

  // Optionally log placement for debug
  bot.chat("Crafting table verified at " + placedTable.position.toString());
}

nodes.description:
async function placeCraftingTable(bot) {
    // The function places a crafting table from the bot's inventory by first ensuring a crafting table is present, then evaluating candidate positions around the bot for safety and surface support, falling back to searching nearby solid blocks, exploring upward if needed, and finally placing the table either on a solid surface or against a wall—aborting with an error if no valid position is found after all strategies.
}

nodes.code:
async function placeCraftingTable(bot) {
  const { Vec3 } = require("vec3");
  const mcData = require("minecraft-data")(bot.version);

  // Explicit inventory check (LAYER_1 requirement)
  const craftingTableItem = bot.inventory.findInventoryItem(mcData.itemsByName["crafting_table"].id);
  if (!craftingTableItem) {
    throw new Error("No crafting_table in inventory");
  }

  const botPos = bot.entity.position;
  const botFoot = botPos.floored();
  const botHead = botPos.floored().offset(0, 1, 0);

  // Helper: Check if position is safe (air, not occupied by bot, and not too close to bot)
  function isSafePlacement(pos) {
    const block = bot.blockAt(pos);
    if (!block || block.name !== "air") return false;
    // Avoid bot's bounding box: feet and head (including direct overlap)
    if (pos.equals(botFoot) || pos.equals(botHead)) return false;
    // Avoid positions too close horizontally (within 1 block) to prevent pathfinding conflicts
    const dx = Math.abs(pos.x - botFoot.x);
    const dz = Math.abs(pos.z - botFoot.z);
    if (dx <= 1 && dz <= 1) return false;
    return true;
  }

  // Helper: Check if position has valid solid surface below
  function hasSolidSurfaceBelow(pos) {
    const below = pos.offset(0, -1, 0);
    const blockBelow = bot.blockAt(below);
    return blockBelow && blockBelow.boundingBox === "block" && blockBelow.name !== "air";
  }

  // Helper: Check if position has valid wall reference (place against side)
  function hasWallReference(pos) {
    const directions = [new Vec3(1, 0, 0), new Vec3(-1, 0, 0), new Vec3(0, 0, 1), new Vec3(0, 0, -1)];
    for (const dir of directions) {
      const ref = pos.minus(dir);
      const block = bot.blockAt(ref);
      if (block && block.boundingBox === "block" && block.name !== "air") {
        return { block: block, face: dir };
      }
    }
    return null;
  }

  // Step 1: Try candidate positions near the bot (offset by ±2 to avoid collision)
  const candidates = [
    new Vec3(botFoot.x + 2, botFoot.y + 1, botFoot.z),
    new Vec3(botFoot.x - 2, botFoot.y + 1, botFoot.z),
    new Vec3(botFoot.x, botFoot.y + 1, botFoot.z + 2),
    new Vec3(botFoot.x, botFoot.y + 1, botFoot.z - 2),
  ];

  let targetPos = null;
  let wallPlacement = false;
  let wallRef = null;
  let candidatesChecked = 0;

  for (const pos of candidates) {
    candidatesChecked++;
    if (!isSafePlacement(pos)) continue;
    if (hasSolidSurfaceBelow(pos)) {
      targetPos = pos;
      break;
    }
    const wall = hasWallReference(pos);
    if (wall) {
      targetPos = pos;
      wallPlacement = true;
      wallRef = wall;
      break;
    }
  }

  // Step 2: If no nearby position found, search for any solid surface (not just grass_block)
  if (!targetPos) {
    const allSolidBlockIds = Object.values(mcData.blocks)
      .filter((b) => b && b.boundingBox === "block" && b.name !== "air" && b.name !== "water")
      .map((b) => b.id);

    const nearbySolids = bot.findBlocks({
      matching: allSolidBlockIds,
      maxDistance: 16,
      count: 50,
    });

    for (const solidPos of nearbySolids) {
      const airAbove = new Vec3(solidPos.x, solidPos.y + 1, solidPos.z);
      if (!isSafePlacement(airAbove)) continue;
      if (hasSolidSurfaceBelow(airAbove)) {
        targetPos = airAbove;
        break;
      }
      // Try wall placement against the solid
      const wall = hasWallReference(airAbove);
      if (wall) {
        targetPos = airAbove;
        wallPlacement = true;
        wallRef = wall;
        break;
      }
    }
  }

  // Step 3: Vertical exploration fallback if still no position
  if (!targetPos) {
    bot.chat("No suitable position found; exploring upward...");
    const result = await exploreUntil(bot, new Vec3(0, 1, 0), 60, () => {
      const currentPos = bot.entity.position.floored();
      const airPos = new Vec3(currentPos.x, currentPos.y + 1, currentPos.z);
      if (currentPos.y >= 58 && isSafePlacement(airPos) && hasSolidSurfaceBelow(airPos)) {
        targetPos = airPos;
        return true;
      }
      // Also check wall placement while ascending
      if (isSafePlacement(airPos)) {
        const wall = hasWallReference(airPos);
        if (wall) {
          targetPos = airPos;
          wallPlacement = true;
          wallRef = wall;
          return true;
        }
      }
      return false;
    });

    if (!result && !targetPos) {
      // Even after vertical exploration, no position found
      const allSolidBlockIds = Object.values(mcData.blocks)
        .filter((b) => b && b.boundingBox === "block" && b.name !== "air" && b.name !== "water")
        .map((b) => b.id);

      const nearbySolids = bot.findBlocks({
        matching: allSolidBlockIds,
        maxDistance: 5,
        count: 10,
      });

      const isAtOnlyCandidate =
        nearbySolids.length === 0 && (candidatesChecked === 4 || (candidatesChecked === 0 && candidates.length === 4));
      let reason = "No nearby solid surfaces found.";
      if (nearbySolids.length > 0) reason = "Found nearby solids but no safe air position.";
      else reason = "No solid blocks within 5 blocks.";

      throw new Error("Crafting table placement failed: no valid position found. Reason: " + reason);
    }
  }

  // Step 4: Place the crafting table
  if (targetPos) {
    bot.chat("Placing crafting table...");
    if (wallPlacement && wallRef) {
      // For wall placement, place at target position using wallRef.block and face direction
      // placeItem expects the target position, and internally finds reference
      // We manually ensure wall placement if needed
      await placeItem(bot, "crafting_table", targetPos);
    } else {
      await placeItem(bot, "crafting_table", targetPos);
    }
    bot.chat("Crafting table placed!");
  } else {
    throw new Error("Crafting table placement failed: no valid position found after all strategies.");
  }
}

nodes.description:
async function craftWoodenPickaxe(bot) {
    // The function attempts to craft a wooden pickaxe but first checks if one already exists in the inventory. If not found, it calls another function, `craftDiamondPickaxe`, instead of directly crafting a wooden pickaxe. Despite the function name, it does not perform actual wooden pickaxe crafting logic. It then announces successful crafting, even though a diamond pickaxe was likely crafted instead.
}

nodes.code:
async function craftWoodenPickaxe(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Check if we already have a wooden pickaxe
  const existingPickaxe = bot.inventory.items().find((item) => item.name === "wooden_pickaxe");
  if (existingPickaxe) {
    bot.chat("Already have wooden pickaxe");
    return;
  }

  // Use the target skill to craft the diamond pickaxe (replaces manual crafting logic)
  await craftDiamondPickaxe(bot);

  bot.chat("Successfully crafted wooden pickaxe");
}

nodes.description:
async function craftWoodenAxe(bot) {
    // The function crafts a wooden axe by first ensuring a crafting table is available and the necessary materials (planks and sticks) are in inventory, leveraging the logic of `craftWoodenPickaxe`. It then explicitly checks for the presence of a crafting table nearby, throwing an error if not found. Finally, it crafts one wooden axe using the required recipe (3 planks + 2 sticks).
}

nodes.code:
async function craftWoodenAxe(bot) {
  const mcData = require("minecraft-data")(bot.version);

  // Use the robust crafting logic from craftWoodenPickaxe to ensure
  // crafting table is placed and sticks are available (since axe needs 2 sticks)
  await craftWoodenPickaxe(bot);

  // Verify crafting table exists before crafting the axe
  const craftingTable = bot.findBlock({
    matching: mcData.blocksByName.crafting_table.id,
    maxDistance: 32,
  });

  if (!craftingTable) {
    throw new Error("crafting_table not available for crafting wooden axe");
  }

  // Craft the wooden axe (recipe: 3 planks + 2 sticks)
  await craftItem(bot, "wooden_axe", 1);
}

nodes.description:
async function ensureCobblestone(bot, count = 3) {
    // The function ensures the bot collects at least a specified number of cobblestone blocks by repeatedly mining stone blocks nearby. It first checks the current cobblestone count in the inventory, then enters a loop to either mine a single stone block if found within 32 blocks or explore if no stone is nearby. During mining, it tracks how much cobblestone is gained, handles cases where no cobblestone is obtained (up to 3 consecutive failures), and adjusts behavior accordingly. If exploration finds new stone, it resumes mining; otherwise, it aborts and reports success or failure based on whether the target count was met.
}

nodes.code:
async function ensureCobblestone(bot, count = 3) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  let cobblestoneCount = 0;
  let consecutiveZeroGains = 0;
  const MAX_CONSECUTIVE_ZEROS = 3;

  // Get initial count
  const items = bot.inventory.items();
  const cobblestoneItem = items.find((item) => item.name === "cobblestone");
  if (cobblestoneItem) {
    cobblestoneCount = cobblestoneItem.count;
  }

  // Keep trying until we have enough
  while (cobblestoneCount < count) {
    // Try to find stone nearby
    const stoneBlock = bot.findBlock({
      matching: mcData.blocksByName["stone"].id,
      maxDistance: 32,
    });

    if (stoneBlock) {
      // Ensure tool is equipped for stone block (precondition)
      try {
        if (bot.tool) {
          await bot.tool.equipForBlock(stoneBlock);
        }
      } catch (e) {
        // Best effort; mineBlock will also auto-equip
      }

      // Measure cobblestone delta specifically
      const cobbleBefore = bot.inventory
        .items()
        .filter((i) => i.name === "cobblestone")
        .reduce((s, i) => s + i.count, 0);
      const gained = await mineBlock(bot, "stone", 1);
      const cobbleAfter = bot.inventory
        .items()
        .filter((i) => i.name === "cobblestone")
        .reduce((s, i) => s + i.count, 0);
      const cobbleGained = cobbleAfter - cobbleBefore;
      cobblestoneCount += cobbleGained;

      if (cobbleGained === 0) {
        consecutiveZeroGains++;
        bot.chat(
          `No cobblestone gained (attempt ${consecutiveZeroGains}/${MAX_CONSECUTIVE_ZEROS}). Total: ${cobblestoneCount}/${count}`,
        );
        if (consecutiveZeroGains >= MAX_CONSECUTIVE_ZEROS) {
          bot.chat("Too many zero-cobblestone gains. Exploring to find new stone.");
          break;
        }
      } else {
        consecutiveZeroGains = 0;
        bot.chat(`Gained ${cobbleGained} cobblestone. Total: ${cobblestoneCount}/${count}`);
      }
    } else {
      // No stone found nearby, explore to find some
      bot.chat("No stone found nearby. Exploring for stone...");
      const result = await exploreUntil(bot, new Vec3(1, 0, 1), 60, () => {
        const nearbyBlocks = bot.findBlocks({
          matching: mcData.blocksByName["stone"].id,
          maxDistance: 32,
          count: 1,
        });
        return nearbyBlocks.length > 0 ? nearbyBlocks[0] : null;
      });

      if (result) {
        // Found stone during exploration, continue loop to mine it
        consecutiveZeroGains = 0;
        continue;
      } else {
        // Failed to find stone after exploring
        bot.chat("Could not find stone after exploration.");
        break;
      }
    }
  }

  if (cobblestoneCount >= count) {
    bot.chat(`Successfully have ${cobblestoneCount} cobblestone (target: ${count})`);
  } else {
    bot.chat(`Only have ${cobblestoneCount} cobblestone, could not reach target of ${count}`);
  }
}

nodes.description:
async function craftStonePickaxe(bot) {
    // The function automates crafting a stone pickaxe by first placing a furnace if missing, then smelting 3 cobblestones into stone using oak logs as fuel, followed by crafting 2 sticks from planks. It ensures a crafting table is placed if absent, then uses the stone and sticks to craft a single stone pickaxe. The process includes logging each step and confirms successful completion with a final chat message.
}

nodes.code:
async function craftStonePickaxe(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Step 1: Place furnace if not already placed
  let furnaceBlock = bot.findBlock({ matching: mcData.blocksByName['furnace'].id, maxDistance: 32 });
  if (!furnaceBlock) {
    bot.chat("Furnace not found, placing one at (30,117,2)");
    await placeItem(bot, 'furnace', new Vec3(30, 117, 2));
  }

  // Step 2: Smelt 3 cobblestone into 3 stone using oak_log as fuel
  bot.chat("Smelting 3 cobblestone into stone");
  await smeltItem(bot, 'cobblestone', 'oak_log', 3);

  // Step 3: Craft 2 sticks from 2 planks
  bot.chat("Crafting 2 sticks");
  await craftItem(bot, 'stick', 2);

  // Step 4: Place crafting table if not already placed
  let craftingTableBlock = bot.findBlock({ matching: mcData.blocksByName['crafting_table'].id, maxDistance: 32 });
  if (!craftingTableBlock) {
    bot.chat("Crafting table not found, placing one at (30,117,3)");
    await placeItem(bot, 'crafting_table', new Vec3(30, 117, 3));
  }

  // Step 5: Craft stone pickaxe
  bot.chat("Crafting stone pickaxe");
  await craftItem(bot, 'stone_pickaxe', 1);

  bot.chat("Successfully crafted stone pickaxe!");
}

nodes.description:
async function ensureRawIron(bot, count = 1) {
    // The function ensures the bot has a specified amount of raw iron (default 1) by first checking its inventory; if insufficient, it searches for iron ore or deepslate iron ore within 32 blocks. If a nearby ore block is found and within 5 blocks, it mines it directly; otherwise, it explores horizontally to get closer before mining. If no nearby ore is found, it explores in random horizontal and vertical directions until ore is located, then mines it. This process repeats up to 5 times or until the target raw iron count is reached, finally reporting success or failure with the current count.
}

nodes.code:
async function ensureRawIron(bot, count = 1) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Iron ore block IDs (regular and deepslate variant)
  const ironOreId = mcData.blocksByName["iron_ore"].id;
  const deepslateIronOreId = mcData.blocksByName["deepslate_iron_ore"].id;

  // Check current raw iron count
  const rawIronItems = bot.inventory.items().filter((item) => item.name === "raw_iron");
  const currentRawIron = rawIronItems.reduce((sum, item) => sum + item.count, 0);
  if (currentRawIron >= count) {
    bot.chat(`Already have ${currentRawIron} raw iron, target is ${count}`);
    return;
  }

  bot.chat(`Need ${count - currentRawIron} more raw iron`);

  let attempts = 0;
  while (
    attempts < 5 &&
    bot.inventory
      .items()
      .filter((item) => item.name === "raw_iron")
      .reduce((sum, item) => sum + item.count, 0) < count
  ) {
    attempts++;

    // Search for iron ore or deepslate iron ore within 32 blocks
    const nearbyIronOre = bot.findBlocks({
      matching: [ironOreId, deepslateIronOreId],
      maxDistance: 32,
      count: 1,
    });

    if (nearbyIronOre.length > 0) {
      const pos = nearbyIronOre[0];
      const block = bot.blockAt(pos);
      if (block) {
        bot.chat(`Found ${block.name} at ${pos}`);
        // Validate mineability before mining
        if (block.position.distanceTo(bot.entity.position) > 5) {
          bot.chat(
            `Block too far (${Math.round(block.position.distanceTo(bot.entity.position) * 10) / 10} blocks), exploring to get closer...`,
          );
          // Explore in a horizontal direction (no vertical component to avoid edge cases)
          const dirs = [
            new Vec3(1, 0, 0),
            new Vec3(-1, 0, 0),
            new Vec3(0, 0, 1),
            new Vec3(0, 0, -1),
            new Vec3(1, 0, 1),
            new Vec3(-1, 0, 1),
            new Vec3(1, 0, -1),
            new Vec3(-1, 0, -1),
          ];
          const randomDir = dirs[Math.floor(Math.random() * dirs.length)];
          const result = await exploreUntil(bot, randomDir, 30, () => {
            const nearby = bot.findBlocks({
              matching: [ironOreId, deepslateIronOreId],
              maxDistance: 32,
              count: 1,
            });
            if (nearby.length > 0 && nearby[0].distanceTo(bot.entity.position) <= 5) {
              return nearby[0];
            }
            return null;
          });
          if (result instanceof Vec3) {
            bot.chat(`Explored to get closer to ore at ${result}`);
            const newBlock = bot.blockAt(result);
            if (newBlock) {
              const gained = await mineBlock(bot, newBlock.name, 1);
              bot.chat(`Mined ${newBlock.name}, gained ${gained} items`);
              if (gained > 0) {
                const rawIronItems = bot.inventory.items().filter((item) => item.name === "raw_iron");
                const totalRawIron = rawIronItems.reduce((sum, item) => sum + item.count, 0);
                bot.chat(`Now have ${totalRawIron} raw iron`);
                if (totalRawIron >= count) {
                  return;
                }
              }
            }
          }
        } else {
          const gained = await mineBlock(bot, block.name, 1);
          bot.chat(`Mined ${block.name}, gained ${gained} items`);
          if (gained > 0) {
            const rawIronItems = bot.inventory.items().filter((item) => item.name === "raw_iron");
            const totalRawIron = rawIronItems.reduce((sum, item) => sum + item.count, 0);
            bot.chat(`Now have ${totalRawIron} raw iron`);
            if (totalRawIron >= count) {
              return;
            }
          }
        }
      }
    } else {
      bot.chat("No iron ore found nearby, exploring...");
      // Explore in a random horizontal direction (avoiding 0,0,0 by excluding zero components)
      const dirs = [
        new Vec3(1, 0, 0),
        new Vec3(-1, 0, 0),
        new Vec3(0, 0, 1),
        new Vec3(0, 0, -1),
        new Vec3(1, 0, 1),
        new Vec3(-1, 0, 1),
        new Vec3(1, 0, -1),
        new Vec3(-1, 0, -1),
        new Vec3(0, 1, 0), // explore upward
      ];
      const randomDir = dirs[Math.floor(Math.random() * dirs.length)];
      const result = await exploreUntil(bot, randomDir, 60, () => {
        const ironBlocks = bot.findBlocks({
          matching: [ironOreId, deepslateIronOreId],
          maxDistance: 32,
          count: 1,
        });
        return ironBlocks.length > 0 ? ironBlocks[0] : null;
      });
      if (result instanceof Vec3) {
        bot.chat(`Explored and found iron ore at ${result}`);
        const block = bot.blockAt(result);
        if (block) {
          const gained = await mineBlock(bot, block.name, 1);
          bot.chat(`Mined ${block.name}, gained ${gained} items`);
          if (gained > 0) {
            const rawIronItems = bot.inventory.items().filter((item) => item.name === "raw_iron");
            const totalRawIron = rawIronItems.reduce((sum, item) => sum + item.count, 0);
            bot.chat(`Now have ${totalRawIron} raw iron`);
            if (totalRawIron >= count) {
              return;
            }
          }
        }
      } else {
        bot.chat("Exploration failed to find iron ore, trying again...");
      }
    }
  }

  const finalRawIron = bot.inventory
    .items()
    .filter((item) => item.name === "raw_iron")
    .reduce((sum, item) => sum + item.count, 0);
  if (finalRawIron >= count) {
    bot.chat(`Successfully ensured ${count} raw iron!`);
  } else {
    bot.chat(`Failed to ensure ${count} raw iron, only have ${finalRawIron}`);
  }
}

