async function smelt3IronIngot(bot) {
    // The function smelts 3 raw iron ingots into iron ingots using a furnace and oak log as fuel. First, it checks if a furnace is already placed nearby (within 32 blocks); if not, it attempts to place one at a valid adjacent or vertical position, ensuring placement safety conditions like avoiding bedrock, respecting minimum distance from the bot, and preventing unsafe upward placement in low Y regions. After successfully placing or confirming the furnace's presence, it proceeds to smelt exactly 3 raw iron items using oak logs as fuel.
}

nodes.code:
async function smelt3IronIngot(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Step 1: Place the furnace if not already placed nearby
  const furnaceBlock = bot.findBlock({
    matching: mcData.blocksByName["furnace"].id,
    maxDistance: 32,
  });

  if (!furnaceBlock) {
    const pos = bot.entity.position;
    const potentialPositions = [
      new Vec3(Math.floor(pos.x) + 1, Math.floor(pos.y), Math.floor(pos.z)),
      new Vec3(Math.floor(pos.x) - 1, Math.floor(pos.y), Math.floor(pos.z)),
      new Vec3(Math.floor(pos.x), Math.floor(pos.y), Math.floor(pos.z) + 1),
      new Vec3(Math.floor(pos.x), Math.floor(pos.y), Math.floor(pos.z) - 1),
      new Vec3(Math.floor(pos.x), Math.floor(pos.y) + 1, Math.floor(pos.z)), // above
      new Vec3(Math.floor(pos.x), Math.floor(pos.y) - 1, Math.floor(pos.z)), // below
    ];

    let placed = false;
    for (let targetPos of potentialPositions) {
      try {
        // Check 1: Ensure target position Y > -63 (not on or below bedrock)
        if (targetPos.y <= -63) continue;

        // Check 2: Verify reference blocks for placement are not bedrock
        const faceVectors = [
          new Vec3(0, 1, 0),
          new Vec3(0, -1, 0),
          new Vec3(1, 0, 0),
          new Vec3(-1, 0, 0),
          new Vec3(0, 0, 1),
          new Vec3(0, 0, -1),
        ];

        let validReference = false;
        for (const vector of faceVectors) {
          const refBlock = bot.blockAt(targetPos.minus(vector));
          if (refBlock && refBlock.name !== "bedrock" && refBlock.name !== "air") {
            validReference = true;
            break;
          }
        }
        if (!validReference) continue;

        // Check 3: Avoid upward placement when Y <= -62
        if (targetPos.y <= -62) {
          const isUpward =
            targetPos.y > Math.floor(pos.y) && targetPos.x === Math.floor(pos.x) && targetPos.z === Math.floor(pos.z);
          if (isUpward) continue;
        }

        // Check 4: Ensure target is at least 1 block away from bot's current position
        if (targetPos.distanceTo(pos) < 1) continue;

        await placeItem(bot, "furnace", targetPos);
        placed = true;
        bot.chat("Placed furnace.");
        break;
      } catch (e) {
        // Try next position
      }
    }

    if (!placed) {
      bot.chat("Failed to place furnace.");
      return;
    }
  }

  // Step 2: Smelt 3 raw_iron into iron_ingot using oak_log as fuel
  await smeltItem(bot, "raw_iron", "oak_log", 3);
  bot.chat("Successfully smelted 3 iron ingots.");
}

