async function craftIronPickaxe(bot) {
    // The function crafts an iron pickaxe by first ensuring a crafting table is placed nearby. If no crafting table is within range, it attempts to place one from the inventory in an adjacent valid location. Once the crafting table is available, it verifies proximity to the table and uses a robust crafting routine to craft one iron pickaxe. The function then checks if the iron pickaxe was successfully added to the inventory and logs the result. Errors during placement or crafting are caught and reported, with the error re-thrown for higher-level handling.
}

nodes.code:
async function craftIronPickaxe(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Helper: place a crafting table if none is nearby
  async function ensureCraftingTableNearby() {
    const nearbyTable = bot.findBlock({
      matching: mcData.blocksByName['crafting_table'].id,
      maxDistance: 32
    });
    if (nearbyTable) {
      return; // already have one nearby
    }
    // Need to place a crafting table
    const craftingTableItem = bot.inventory.findInventoryItem(mcData.itemsByName['crafting_table'].id);
    if (!craftingTableItem) {
      bot.chat("I don't have a crafting_table in inventory to place.");
      return;
    }
    // Find a valid position to place the crafting table adjacent to bot
    const botPos = bot.entity.position;
    const directions = [
      new Vec3(1, 0, 0), new Vec3(-1, 0, 0),
      new Vec3(0, 0, 1), new Vec3(0, 0, -1)
    ];
    for (const dir of directions) {
      const targetPos = botPos.clone().add(dir);
      if (bot.blockAt(targetPos)?.type === undefined || bot.blockAt(targetPos)?.type === 0) {
        try {
          await placeItem(bot, 'crafting_table', targetPos);
          bot.chat("Placed a crafting table.");
          return;
        } catch (err) {
          // try next direction
          continue;
        }
      }
    }
    bot.chat("Could not find a suitable spot to place the crafting table.");
  }

  // Step 1: Ensure crafting table is placed nearby
  await ensureCraftingTableNearby();

  // Step 2: Craft the iron pickaxe using the robust crafting logic from craftDiamondPickaxe
  try {
    // Use the same crafting logic pattern as craftDiamondPickaxe
    // Check if crafting table is nearby
    const craftingTableBlock = bot.findBlock({
      matching: mcData.blocksByName['crafting_table'].id,
      maxDistance: 32
    });

    if (!craftingTableBlock) {
      bot.chat("Crafting table is not nearby. Cannot craft iron pickaxe.");
      return;
    }

    // Perform crafting
    await craftItem(bot, 'iron_pickaxe', 1);
    bot.chat("Crafted 1 iron pickaxe successfully.");

    // Verify the iron pickaxe is in inventory
    const ironPickaxeItem = bot.inventory.findInventoryItem(mcData.itemsByName['iron_pickaxe'].id);
    if (ironPickaxeItem) {
      bot.chat(`Successfully crafted iron pickaxe. Have ${ironPickaxeItem.count} in inventory.`);
    } else {
      bot.chat("Warning: iron pickaxe crafting completed but item not found in inventory.");
    }
  } catch (err) {
    bot.chat("Failed to craft iron pickaxe: " + err.message);
    throw err;
  }
}

nodes.description:
async function ensureDiamonds(bot, count = 3) {
    // The function attempts to collect a specified number of diamonds by exploring and mining diamond ore blocks. It first checks if enough diamonds are already in the inventory; if not, it descends to Y=-59, the optimal depth for diamond ore. Then it explores horizontally at that depth until diamond ore (diamond_ore or deepslate_diamond_ore) is found within range. Once found, it mines exactly one block of the ore and checks if the resulting diamonds meet the target count. This process repeats up to five times, giving up and reporting failure if the target isn’t reached after all attempts.
}

nodes.code:
async function ensureDiamonds(bot, count = 3) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Helper function to get diamond ore block ID(s)
  function getDiamondOreIds() {
    const ids = [];
    if (mcData.blocksByName["diamond_ore"]) ids.push(mcData.blocksByName["diamond_ore"].id);
    if (mcData.blocksByName["deepslate_diamond_ore"]) ids.push(mcData.blocksByName["deepslate_diamond_ore"].id);
    return ids;
  }

  // Helper function to descend to target Y in unit steps (dy=-1 per call)
  async function descendToY(bot, targetY) {
    const maxDescentAttempts = 20;
    let attempts = 0;
    const direction = new Vec3(0, -1, 0); // Unit vertical direction
    while (bot.entity.position.y > targetY && attempts < maxDescentAttempts) {
      await exploreUntil(bot, direction, 30, () => {
        return bot.entity.position.y <= targetY ? true : null;
      });
      attempts++;
    }
    if (attempts >= maxDescentAttempts) {
      bot.chat("Descent failed after max attempts, proceeding anyway.");
    }
  }

  // Main loop: keep trying until we have enough diamonds
  let attempts = 0;
  const maxAttempts = 5;

  while (attempts < maxAttempts) {
    // Check current inventory for diamonds
    const diamondItems = bot.inventory.items().filter((item) => item.name === "diamond");
    const currentDiamonds = diamondItems.reduce((sum, item) => sum + item.count, 0);

    if (currentDiamonds >= count) {
      bot.chat(`I already have ${currentDiamonds} diamonds, task complete.`);
      return;
    }

    // Descend to optimal diamond depth (Y=-59)
    await descendToY(bot, -59);

    bot.chat(`Exploring horizontally at Y=${bot.entity.position.y.toFixed(0)} for diamond ore...`);

    // Explore horizontally
    const found = await exploreUntil(bot, new Vec3(1, 0, 0), 60, () => {
      const ids = getDiamondOreIds();
      if (ids.length === 0) {
        bot.chat("Error: diamond_ore not found in mcData");
        return true;
      }
      const blocks = bot.findBlocks({ matching: ids, maxDistance: 32, count: 1 });
      if (blocks && blocks.length > 0 && blocks[0]) {
        const blockPos = blocks[0];
        if (typeof blockPos.x === "number" && typeof blockPos.y === "number" && typeof blockPos.z === "number") {
          bot.chat(`Found diamond ore at ${blockPos.x}, ${blockPos.y}, ${blockPos.z}`);
          return blockPos;
        }
      }
      return null;
    });

    // Defensive check for found position
    if (!found || typeof found.x !== "number" || typeof found.y !== "number" || typeof found.z !== "number") {
      bot.chat("No diamond ore found after horizontal exploration.");
      attempts++;
      continue;
    }

    // Extract position safely with defensive checks
    const pos = new Vec3(found.x, found.y, found.z);
    const block = bot.blockAt(pos);

    // Explicit guard for block existence and validity
    if (!block || typeof block.name !== "string" || block.name === "") {
      bot.chat(`Could not identify block at found position ${pos.toString()}`);
      attempts++;
      continue;
    }

    // Use detected block name (diamond_ore or deepslate_diamond_ore)
    const blockName = block.name;
    bot.chat(`Mining ${blockName} at ${pos.x}, ${pos.y}, ${pos.z}...`);

    const mined = await mineBlock(bot, blockName, 1);
    bot.chat(`Mined ${mined} items from ${blockName}`);

    // Check if we got diamonds
    const afterMinedItems = bot.inventory.items().filter((item) => item.name === "diamond");
    const afterMinedCount = afterMinedItems.reduce((sum, item) => sum + item.count, 0);

    if (afterMinedCount >= count) {
      bot.chat(`Success! I now have ${afterMinedCount} diamonds.`);
      return;
    }

    // If still need more, continue loop
    attempts++;
  }

  // Final check
  const finalDiamondItems = bot.inventory.items().filter((item) => item.name === "diamond");
  const finalDiamonds = finalDiamondItems.reduce((sum, item) => sum + item.count, 0);

  if (finalDiamonds >= count) {
    bot.chat(`Successfully ensured ${finalDiamonds} diamonds.`);
  } else {
    bot.chat(`Failed to ensure ${count} diamonds. I have ${finalDiamonds}.`);
  }
}

async function craftDiamondPickaxe(bot) {
  const mcData = require("minecraft-data")(bot.version);

  // Step 1: Check if a crafting table is already placed nearby
  const craftingTableBlock = bot.findBlock({
    matching: mcData.blocksByName['crafting_table'].id,
    maxDistance: 32
  });

  let needsPlacement = false;
  if (!craftingTableBlock) {
    needsPlacement = true;
  }

  // Step 2: If no crafting table is placed, place one from inventory
  if (needsPlacement) {
    const craftingTableItem = bot.inventory.findInventoryItem(mcData.itemsByName['crafting_table'].id);
    if (!craftingTableItem) {
      bot.chat("Error: No crafting_table in inventory to place!");
      return;
    }

    // Find a safe position to place the crafting table (nearby air position)
    const botPos = bot.entity.position;
    const safePositions = [
      new Vec3(Math.round(botPos.x) + 1, Math.round(botPos.y), Math.round(botPos.z)),
      new Vec3(Math.round(botPos.x) - 1, Math.round(botPos.y), Math.round(botPos.z)),
      new Vec3(Math.round(botPos.x), Math.round(botPos.y), Math.round(botPos.z) + 1),
      new Vec3(Math.round(botPos.x), Math.round(botPos.y), Math.round(botPos.z) - 1)
    ];

    let placed = false;
    for (const pos of safePositions) {
      // Check if position is AIR (or water, but unlikely here) and not bedrock/deepslate
      const blockAtPos = bot.blockAt(pos);
      if (blockAtPos && blockAtPos.name === 'air') {
        try {
          await placeItem(bot, 'crafting_table', pos);
          bot.chat("Placed crafting_table for diamond pickaxe crafting.");
          placed = true;
          break;
        } catch (e) {
          // Try next position
          continue;
        }
      }
    }

    if (!placed) {
      bot.chat("Could not find a safe position to place crafting_table. Trying nearby air.");
      // Try to find any nearby air block (not limited to cardinal directions)
      for (let dx = -2; dx <= 2; dx++) {
        for (let dz = -2; dz <= 2; dz++) {
          const pos = new Vec3(Math.round(botPos.x) + dx, Math.round(botPos.y), Math.round(botPos.z) + dz);
          if (bot.blockAt(pos)?.name === 'air') {
            try {
              await placeItem(bot, 'crafting_table', pos);
              bot.chat("Placed crafting_table for diamond pickaxe crafting (alternative position).");
              placed = true;
              break;
            } catch (e) {
              continue;
            }
          }
        }
        if (placed) break;
      }
    }

    if (!placed) {
      bot.chat("Failed to place crafting_table. Aborting diamond pickaxe crafting.");
      return;
    }
  }

  // Step 3: Craft the diamond_pickaxe
  try {
    await craftItem(bot, 'diamond_pickaxe', 1);
    bot.chat("Crafted 1 diamond_pickaxe.");
  } catch (e) {
    bot.chat("Failed to craft diamond_pickaxe: " + e.message);
    return;
  }

  // Step 4: Verify the diamond_pickaxe is in inventory
  const diamondPickaxeItem = bot.inventory.findInventoryItem(mcData.itemsByName['diamond_pickaxe'].id);
  if (diamondPickaxeItem) {
    bot.chat(`Successfully crafted diamond_pickaxe. Have ${diamondPickaxeItem.count} in inventory.`);
  } else {
    bot.chat("Warning: diamond_pickaxe crafting completed but item not found in inventory.");
  }
}

