nodes.description:
async function mineDeepslateLapisOre(bot, count = 3) {
    // The function mines deepslate lapis ore to collect a specified number of lapis lazuli items (default 3 blocks’ worth, assuming at least 4 drops per block). It first checks if enough lapis lazuli is already in the inventory; if not, it attempts to find and mine ore within 32 blocks, equipping the appropriate pickaxe and handling proximity or pathfinding as needed. If no ore is nearby, it explores downward (focusing on Y=-19 to -32), then horizontally if downward fails, repeating the search up to 10 times. After each mining attempt, it updates the collected count and verifies drops. Finally, it reports success or failure based on whether the target item count was met.
}

nodes.code:
async function mineDeepslateLapisOre(bot, count = 3) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  const targetItemName = "lapis_lazuli";
  const oreBlockName = "deepslate_lapis_ore";
  const MIN_DROPS_PER_BLOCK = 4;
  const targetItems = count * MIN_DROPS_PER_BLOCK;

  // Early exit: check if enough lapis_lazuli is already in inventory
  const lapisItems = bot.inventory.items().filter((item) => item.name === targetItemName);
  const currentLapis = lapisItems.reduce((sum, item) => sum + item.count, 0);
  if (currentLapis >= targetItems) {
    bot.chat(`Already have ≥${targetItems} lapis_lazuli (≥${count} blocks worth).`);
    return true;
  }
  bot.chat(`Need ${targetItems - currentLapis} more lapis_lazuli for ${count} blocks.`);

  let collectedItems = 0;
  let attempts = 0;
  const maxAttempts = 10;

  while (collectedItems < targetItems && attempts < maxAttempts) {
    attempts++;

    bot.chat(`Collected ${collectedItems}/${targetItems} lapis_lazuli. Searching for ${oreBlockName}...`);

    // Search for deepslate_lapis_ore within 32 blocks
    const oreBlockObj = bot.findBlock({
      matching: mcData.blocksByName[oreBlockName]?.id,
      maxDistance: 32,
      useExtraInfo: false,
    });

    if (oreBlockObj) {
      // Validate positions before distance calculation
      if (!bot.entity?.position) {
        bot.chat("Bot position is undefined, cannot proceed");
        await new Promise((resolve) => setTimeout(resolve, 500));
        continue;
      }

      if (!oreBlockObj.position) {
        bot.chat("Block position is undefined, cannot proceed");
        await new Promise((resolve) => setTimeout(resolve, 500));
        continue;
      }

      try {
        // Auto-equip best tool for deepslate_lapis_ore (requires stone pickaxe or better)
        await bot.tool.equipForBlock(oreBlockObj);

        const dist = oreBlockObj.position.distanceTo(bot.entity.position);

        if (dist <= 4.5) {
          bot.chat(`Found ${oreBlockName} at ${oreBlockObj.position}, mining...`);

          try {
            await bot.dig(oreBlockObj);
            await new Promise((resolve) => setTimeout(resolve, 500));
            await bot.collectBlock.collect(oreBlockObj);
          } catch (digError) {
            bot.chat(`Error mining ${oreBlockName}: ${digError.message}`);
            continue;
          }
        } else {
          bot.chat(`Found ${oreBlockName} at ${oreBlockObj.position} (distance: ${dist.toFixed(2)}), pathfinding...`);

          try {
            await bot.pathfinder.goto(
              new GoalGetToBlock(oreBlockObj.position.x, oreBlockObj.position.y, oreBlockObj.position.z, bot.world),
            );
            // Re-equip tool after pathfinding
            await bot.tool.equipForBlock(oreBlockObj);

            await bot.dig(oreBlockObj);
            await new Promise((resolve) => setTimeout(resolve, 500));
            await bot.collectBlock.collect(oreBlockObj);
          } catch (pathError) {
            bot.chat(`Error pathfinding to ${oreBlockName}: ${pathError.message}`);
            continue;
          }
        }

        // Verify how much lapis we got
        const newLapisItems = bot.inventory.items().filter((item) => item.name === targetItemName);
        const newLapisCount = newLapisItems.reduce((sum, item) => sum + item.count, 0);
        const gained = newLapisCount - collectedItems;

        if (gained > 0) {
          collectedItems += gained;
          bot.chat(`Mined 1 ${oreBlockName}, got ${gained} ${targetItemName}. Total: ${collectedItems}/${targetItems}`);
        } else {
          bot.chat(`Mined ${oreBlockName} but got 0 ${targetItemName} (tool tier issue or missed drop)`);
          const currentBlock = bot.blockAt(oreBlockObj.position);
          if (currentBlock && currentBlock.name === oreBlockName) {
            bot.chat(`Block still present at ${oreBlockObj.position}, mining may have failed`);
          }
        }
      } catch (error) {
        bot.chat(`Error mining ${oreBlockName}: ${error.message}`);
        await new Promise((resolve) => setTimeout(resolve, 1000));
      }
    } else {
      // Prioritize downward exploration for deepslate lapis_ore (best at Y=-19 to -32)
      bot.chat("No deepslate_lapis_ore found nearby. Exploring downward...");

      try {
        const exploreResult = await exploreUntil(bot, new Vec3(0, -1, 0), 60, () => {
          try {
            const nearby = bot.findBlock({
              matching: mcData.blocksByName[oreBlockName]?.id,
              maxDistance: 32,
              useExtraInfo: false,
            });
            return nearby ? { found: true, pos: nearby } : null;
          } catch (e) {
            bot.chat(`Error during exploration search: ${e.message}`);
            return null;
          }
        });

        if (exploreResult && exploreResult.found && exploreResult.pos && exploreResult.pos.position) {
          bot.chat(`Exploration found ${oreBlockName} at ${exploreResult.pos.position}`);

          try {
            if (!bot.entity?.position) {
              bot.chat("Bot position undefined during exploration");
              continue;
            }

            if (!exploreResult.pos.position) {
              bot.chat("Found block position undefined");
              continue;
            }

            const dist = exploreResult.pos.position.distanceTo(bot.entity.position);

            await bot.tool.equipForBlock(exploreResult.pos);

            if (dist <= 4.5) {
              try {
                await bot.dig(exploreResult.pos);
                await new Promise((resolve) => setTimeout(resolve, 500));
                await bot.collectBlock.collect(exploreResult.pos);
              } catch (digError) {
                bot.chat(`Error mining exploration ore: ${digError.message}`);
              }
            } else {
              try {
                await bot.pathfinder.goto(
                  new GoalGetToBlock(
                    exploreResult.pos.position.x,
                    exploreResult.pos.position.y,
                    exploreResult.pos.position.z,
                    bot.world,
                  ),
                );
                await bot.tool.equipForBlock(exploreResult.pos);
                await bot.dig(exploreResult.pos);
                await new Promise((resolve) => setTimeout(resolve, 500));
                await bot.collectBlock.collect(exploreResult.pos);
              } catch (pathError) {
                bot.chat(`Error pathfinding to exploration ore: ${pathError.message}`);
              }
            }
          } catch (error) {
            bot.chat(`Error processing exploration result: ${error.message}`);
          }
        } else {
          bot.chat("Downward exploration did not find deepslate_lapis_ore.");

          // Horizontal exploration as secondary fallback
          const dirs = [new Vec3(1, 0, 0), new Vec3(-1, 0, 0), new Vec3(0, 0, 1), new Vec3(0, 0, -1)];
          const randDir = dirs[Math.floor(Math.random() * dirs.length)];

          bot.chat(`Trying horizontal exploration in direction ${randDir}`);

          try {
            const horizResult = await exploreUntil(bot, randDir, 60, () => {
              try {
                const nearby = bot.findBlock({
                  matching: mcData.blocksByName[oreBlockName]?.id,
                  maxDistance: 32,
                  useExtraInfo: false,
                });
                return nearby ? { found: true, pos: nearby } : null;
              } catch (e) {
                bot.chat(`Error during horizontal search: ${e.message}`);
                return null;
              }
            });

            if (horizResult && horizResult.found && horizResult.pos && horizResult.pos.position) {
              bot.chat(`Horizontal exploration found ${oreBlockName} at ${horizResult.pos.position}`);

              try {
                if (!bot.entity?.position) {
                  bot.chat("Bot position undefined during horizontal exploration");
                  continue;
                }

                if (!horizResult.pos.position) {
                  bot.chat("Found block position undefined");
                  continue;
                }

                const dist = horizResult.pos.position.distanceTo(bot.entity.position);

                await bot.tool.equipForBlock(horizResult.pos);

                if (dist <= 4.5) {
                  try {
                    await bot.dig(horizResult.pos);
                    await new Promise((resolve) => setTimeout(resolve, 500));
                    await bot.collectBlock.collect(horizResult.pos);
                  } catch (digError) {
                    bot.chat(`Error mining horizontal ore: ${digError.message}`);
                  }
                } else {
                  try {
                    await bot.pathfinder.goto(
                      new GoalGetToBlock(
                        horizResult.pos.position.x,
                        horizResult.pos.position.y,
                        horizResult.pos.position.z,
                        bot.world,
                      ),
                    );
                    await bot.tool.equipForBlock(horizResult.pos);
                    await bot.dig(horizResult.pos);
                    await new Promise((resolve) => setTimeout(resolve, 500));
                    await bot.collectBlock.collect(horizResult.pos);
                  } catch (pathError) {
                    bot.chat(`Error pathfinding to horizontal ore: ${pathError.message}`);
                  }
                }
              } catch (error) {
                bot.chat(`Error processing horizontal result: ${error.message}`);
              }
            } else {
              bot.chat("Horizontal exploration also failed to find deepslate_lapis_ore.");
            }
          } catch (error) {
            bot.chat(`Error during horizontal exploration: ${error.message}`);
          }
        }
      } catch (error) {
        bot.chat(`Error during downward exploration: ${error.message}`);
      }
    }
  }

  // Final validation: ensure actual item goal is met
  const finalLapisItems = bot.inventory.items().filter((item) => item.name === targetItemName);
  const finalCount = finalLapisItems.reduce((sum, item) => sum + item.count, 0);

  if (finalCount >= targetItems) {
    bot.chat(`Successfully mined ${finalCount} lapis_lazuli (≥${targetItems} required, ≥${count} blocks worth).`);
    return true;
  } else {
    bot.chat(`Failed to mine ${targetItems} lapis_lazuli (≥${count} blocks worth). Only got ${finalCount}.`);
    return false;
  }
}

async function mineDeepslateDiamondOre(bot, count = 6) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  let totalMined = 0;
  const targetCount = count;

  while (totalMined < targetCount) {
    // Check if we already have enough diamonds in inventory
    const diamondItems = bot.inventory.items().filter(item => item.name === 'diamond');
    const currentDiamonds = diamondItems.reduce((sum, item) => sum + item.count, 0);

    if (currentDiamonds >= targetCount) {
      bot.chat(`Already have ${currentDiamonds} diamonds, task complete.`);
      return;
    }

    // Search for deepslate_diamond_ore blocks (and regular diamond_ore as fallback)
    const diamondOreIDs = [
      mcData.blocksByName['diamond_ore']?.id,
      mcData.blocksByName['deepslate_diamond_ore']?.id
    ].filter(id => id !== undefined);

    const nearbyBlocks = bot.findBlocks({
      matching: diamondOreIDs,
      maxDistance: 32,
      count: 1
    });

    if (nearbyBlocks.length === 0) {
      // No ore found nearby, explore at Y=-59 depth
      bot.chat("No deepslate diamond ore found nearby, exploring...");

      // Explore in a random direction at Y=-59
      const directions = [
        new Vec3(1, 0, 1),
        new Vec3(1, 0, -1),
        new Vec3(-1, 0, 1),
        new Vec3(-1, 0, -1),
        new Vec3(1, 0, 0),
        new Vec3(-1, 0, 0),
        new Vec3(0, 0, 1),
        new Vec3(0, 0, -1)
      ];
      const randomDir = directions[Math.floor(Math.random() * directions.length)];

      // Explore until we find diamond ore or timeout
      const result = await exploreUntil(bot, randomDir, 60, () => {
        const foundBlocks = bot.findBlocks({
          matching: diamondOreIDs,
          maxDistance: 32,
          count: 1
        });
        return foundBlocks.length > 0 ? foundBlocks[0] : null;
      });

      if (!result) {
        bot.chat("Exploration failed to find diamond ore.");
        break;
      }
    } else {
      // Found a block, try to mine it
      const blockPos = nearbyBlocks[0];
      const block = bot.blockAt(blockPos);

      if (!block) {
        continue;
      }

      // Check distance - must be within 4 blocks to mine
      const distance = bot.entity.position.distanceTo(blockPos);
      if (distance > 4) {
        // Pathfind to block first
        try {
          await bot.pathfinder.goto(new GoalGetToBlock(blockPos, bot.world, {}));
        } catch (e) {
          bot.chat(`Failed to pathfind to block: ${e.message}`);
          continue;
        }
      }

      // Mine the block
      try {
        const mined = await mineBlock(bot, block.name, 1);
        if (mined > 0) {
          totalMined += mined;
          bot.chat(`Mined ${block.name}, total deepslate diamond ore: ${totalMined}/${targetCount}`);
        } else {
          bot.chat(`Failed to mine ${block.name}`);
        }
      } catch (e) {
        bot.chat(`Error mining block: ${e.message}`);
      }
    }
  }

  // Final check
  const diamondItems = bot.inventory.items().filter(item => item.name === 'diamond');
  const finalCount = diamondItems.reduce((sum, item) => sum + item.count, 0);
  bot.chat(`Deepslate diamond mining complete. Collected ${finalCount} diamonds.`);
}

