async function mineRedstoneDust(bot) {
    // The function automates collecting 16 redstone dust by first checking inventory space and freeing slots if needed, then ensuring a suitable pickaxe (at least iron) is available—crafting iron ingots and the pickaxe if necessary—before mining redstone ore (deepslate below Y=58, regular above). It validates harvest capability before mining, mines up to 4 ore blocks of the appropriate type, and confirms success by comparing redstone count before and after, throwing an error if the target isn’t met.
}

nodes.code:
async function mineRedstoneDust(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  function countRedstone() {
    return bot.inventory
      .items()
      .filter((item) => item.name === "redstone")
      .reduce((sum, item) => sum + item.count, 0);
  }

  function getToolForBlock(blockName) {
    if (blockName === "redstone_ore" || blockName === "deepslate_redstone_ore") {
      return "iron_pickaxe";
    }
    if (blockName === "iron_ore") {
      return "stone_pickaxe";
    }
    return null;
  }

  const target = 16;
  const initialRedstone = countRedstone();

  if (initialRedstone >= target) {
    bot.chat(`Already have ${initialRedstone} redstone dust, skipping.`);
    return;
  }

  const initialFreeSlots = bot.inventory.emptySlotCount();

  if (initialFreeSlots < 1) {
    bot.chat(`Inventory full (${36 - initialFreeSlots}/36 slots). Attempting to free space...`);

    const lowValueItems = ["cobblestone", "diorite", "andesite", "granite", "deepslate", "dirt", "gravel"];
    let freed = false;

    for (const itemName of lowValueItems) {
      const item = bot.inventory.findInventoryItem(mcData.itemsByName[itemName]?.id);
      if (!item) continue;

      const countToDrop = Math.floor(item.count / 16) * 16;
      if (countToDrop <= 0) continue;

      try {
        await bot.toss(item.type, null, countToDrop);
        await bot.waitForTicks(5);
        if (bot.inventory.emptySlotCount() > initialFreeSlots) {
          bot.chat(`Dropped ${countToDrop} ${itemName} to free inventory space.`);
          freed = true;
          break;
        }
      } catch (e) {
        bot.chat(`Failed to drop ${itemName}: ${e.message}`);
      }
    }

    if (!freed) {
      bot.chat(`Inventory full. Could not free space. Configure chest or clear inventory.`);
      throw new Error("Inventory full, cannot collect redstone. Configure chest or free space.");
    }
  }

  // === Tool acquisition: tier-aware and resource-adaptive ===
  const stonePickaxe = bot.inventory.findInventoryItem(mcData.itemsByName.stone_pickaxe.id);
  const ironPickaxe = bot.inventory.findInventoryItem(mcData.itemsByName.iron_pickaxe.id);
  const diamondPickaxe = bot.inventory.findInventoryItem(mcData.itemsByName.diamond_pickaxe.id);

  const requiredToolForRedstone = getToolForBlock("deepslate_redstone_ore");

  // Ensure we have at least stone pickaxe (or better)
  if (!stonePickaxe && !ironPickaxe && !diamondPickaxe) {
    try {
      await craftStonePickaxe(bot);
    } catch (err) {
      throw new Error(`Failed to craft stone pickaxe: ${err.message}`);
    }
  }

  // Re-check for pickaxes after potential crafting
  const stonePickaxeAfter = bot.inventory.findInventoryItem(mcData.itemsByName.stone_pickaxe.id);
  const ironPickaxeAfter = bot.inventory.findInventoryItem(mcData.itemsByName.iron_pickaxe.id);
  const diamondPickaxeAfter = bot.inventory.findInventoryItem(mcData.itemsByName.diamond_pickaxe.id);

  // If redstone requires iron but we only have stone, try to craft iron pickaxe
  if (requiredToolForRedstone === "iron_pickaxe" && !ironPickaxeAfter && !diamondPickaxeAfter && stonePickaxeAfter) {
    // === Mining iron_ore ===
    let ironOreFound = false;
    const ironOreBlocks = bot.findBlocks({
      matching: mcData.blocksByName.iron_ore.id,
      maxDistance: 32,
      count: 4,
    });

    if (ironOreBlocks.length > 0) {
      try {
        await mineBlock(bot, "iron_ore", 1);
        ironOreFound = true;
      } catch (e) {
        bot.chat(`Failed to mine iron_ore: ${e.message}`);
      }
    }

    // If still no iron_ore, explore for it
    if (!ironOreFound) {
      bot.chat("Exploring for iron_ore...");
      try {
        await exploreUntil(bot, new Vec3(1, 0, 0), 60, () => {
          const found = bot.findBlocks({
            matching: mcData.blocksByName.iron_ore.id,
            maxDistance: 32,
            count: 1,
          });
          return found.length > 0 ? true : null;
        });
        await mineBlock(bot, "iron_ore", 1);
      } catch (e) {
        bot.chat(`Exploration and mining failed: ${e.message}`);
      }
    }

    // === Smelt raw_iron to iron_ingot if raw_iron is available ===
    const rawIronAfterMining = bot.inventory.findInventoryItem(mcData.itemsByName.raw_iron.id);
    if (rawIronAfterMining && rawIronAfterMining.count >= 3) {
      try {
        await smelt3IronIngot(bot);
      } catch (e) {
        bot.chat(`Failed to smelt iron: ${e.message}`);
      }
    }

    // === Prepare to craft iron pickaxe ONLY if iron_ingot is ready ===
    const ironIngotCheck = bot.inventory.findInventoryItem(mcData.itemsByName.iron_ingot.id);
    if (ironIngotCheck && ironIngotCheck.count >= 3) {
      try {
        await craftIronPickaxe(bot);
        // === CALLER-FIX: Re-fetch iron_pickaxe after crafting and equip it explicitly ===
        const ironPickaxeAfterCraft = bot.inventory.findInventoryItem(mcData.itemsByName.iron_pickaxe.id);
        if (ironPickaxeAfterCraft) {
          await bot.equip(ironPickaxeAfterCraft, "hand");
        }
      } catch (e) {
        bot.chat(`Failed to craft iron pickaxe: ${e.message}`);
      }
    } else {
      bot.chat("Insufficient iron_ingot to craft iron pickaxe. Continuing with stone pickaxe.");
    }
  }

  // === Tool tier enforcement: only equip if meets minimum requirement ===
  const stonePickaxeFinal = bot.inventory.findInventoryItem(mcData.itemsByName.stone_pickaxe.id);
  const ironPickaxeFinal = bot.inventory.findInventoryItem(mcData.itemsByName.iron_pickaxe.id);
  const diamondPickaxeFinal = bot.inventory.findInventoryItem(mcData.itemsByName.diamond_pickaxe.id);

  // Prioritize equip for harvest capability (iron required for redstone)
  let equippedPickaxe = null;
  if (diamondPickaxeFinal && (getToolForBlock("deepslate_redstone_ore") === "iron_pickaxe" || true)) {
    await bot.equip(diamondPickaxeFinal, "hand");
    equippedPickaxe = diamondPickaxeFinal;
  } else if (ironPickaxeFinal && getToolForBlock("deepslate_redstone_ore") === "iron_pickaxe") {
    await bot.equip(ironPickaxeFinal, "hand");
    equippedPickaxe = ironPickaxeFinal;
  } else if (stonePickaxeFinal && getToolForBlock("deepslate_redstone_ore") !== "iron_pickaxe") {
    await bot.equip(stonePickaxeFinal, "hand");
    equippedPickaxe = stonePickaxeFinal;
  } else {
    bot.chat("No suitable pickaxe for redstone mining. Need iron_pickaxe or better.");
    throw new Error("No suitable pickaxe for redstone mining. Need iron_pickaxe or better.");
  }

  // === Mining redstone ore (deepslate if Y ≤ 58) ===
  const botY = bot.entity ? bot.entity.position.y : 64;
  let miningSuccessful = false;

  // Check if deepslate_redstone_ore exists first before mining
  if (botY <= 58) {
    const deepslateBlocks = bot.findBlocks({
      matching: mcData.blocksByName.deepslate_redstone_ore.id,
      maxDistance: 32,
      count: 4,
    });

    if (deepslateBlocks.length > 0) {
      try {
        const heldItem = bot.heldItem;
        const deepslateBlock = bot.blockAt(deepslateBlocks[0]);

        // === LAYER 0 - PRECONDITION FIX: Check canHarvest before mining ===
        if (!deepslateBlock.canHarvest(heldItem ? heldItem.type : null)) {
          throw new Error("Cannot mine deepslate_redstone_ore: requires iron_pickaxe or better");
        }

        const before = countRedstone();
        await mineBlock(bot, "deepslate_redstone_ore", 4);
        const after = countRedstone();

        if (after > before) {
          miningSuccessful = true;
          bot.chat(`Gained ${after - before} redstone from deepslate_redstone_ore.`);
        }
      } catch (error) {
        if (error.message.includes("inventory") || error.message.includes("full")) {
          throw error;
        }
        bot.chat(`Failed to mine deepslate_redstone_ore: ${error.message}`);
      }
    } else {
      bot.chat("No deepslate_redstone_ore found nearby");
    }
  }

  // If no gain yet and Y > 58, try surface redstone ore
  if (!miningSuccessful && botY > 58) {
    const surfaceBlocks = bot.findBlocks({
      matching: mcData.blocksByName.redstone_ore.id,
      maxDistance: 32,
      count: 4,
    });

    if (surfaceBlocks.length > 0) {
      try {
        const heldItem = bot.heldItem;
        const surfaceBlock = bot.blockAt(surfaceBlocks[0]);

        // === LAYER 0 - PRECONDITION FIX: Check canHarvest before mining ===
        if (!surfaceBlock.canHarvest(heldItem ? heldItem.type : null)) {
          throw new Error("Cannot mine redstone_ore: requires iron_pickaxe or better");
        }

        const before = countRedstone();
        await mineBlock(bot, "redstone_ore", 4);
        const after = countRedstone();

        if (after > before) {
          miningSuccessful = true;
          bot.chat(`Gained ${after - before} redstone from redstone_ore.`);
        }
      } catch (error) {
        if (error.message.includes("inventory") || error.message.includes("full")) {
          throw error;
        }
        bot.chat(`Failed to mine redstone_ore: ${error.message}`);
      }
    } else {
      bot.chat("No redstone_ore found nearby");
    }
  }

  // Final validation
  const finalRedstone = countRedstone();
  const gainedTotal = finalRedstone - initialRedstone;

  if (gainedTotal >= target) {
    bot.chat(`Successfully collected ${gainedTotal} redstone dust (target: ${target})`);
  } else {
    bot.chat(
      `Failed to collect 16 redstone: only gained ${gainedTotal}. Check ore availability, inventory space, and tool readiness.`,
    );
    throw new Error(`Failed to collect 16 redstone: only gained ${gainedTotal}.`);
  }
}

