async function craftRedstoneTorch(bot) {
    // The function crafts 3 redstone torches by first ensuring a crafting table is placed (retrying at a safe offset if needed), then verifying sufficient sticks (crafting additional sticks from planks if fewer than 3 are available), and finally using the crafting table to craft the redstone torches.
}

nodes.code:
async function craftRedstoneTorch(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Ensure a crafting table is placed and verify it exists in the world
  await craftOakCraftingTable(bot);

  let table = bot.findBlock({ matching: mcData.blocksByName.crafting_table.id, maxDistance: 32 });
  if (!table) {
    // Retry at a safe offset if initial placement failed
    const retryOffset = bot.entity.position.offset(2, 0, 0).floored();
    try {
      await placeItem(bot, "crafting_table", retryOffset);
    } catch (err) {
      throw new Error("Crafting table placement failed and retry at safe offset also failed");
    }

    // Wait a moment for block update to propagate
    await bot.waitForTicks(10);

    table = bot.findBlock({ matching: mcData.blocksByName.crafting_table.id, maxDistance: 32 });
    if (!table) {
      throw new Error("Crafting table placement failed or unconfirmed after retry");
    }
  }

  // Ensure we have enough sticks — if not, craft planks → sticks (2x2, no table required)
  const stickItems = bot.inventory.items().filter((item) => item.name === "stick");
  const stickCount = stickItems.reduce((sum, item) => sum + item.count, 0);
  if (stickCount < 3) {
    // Ensure we have planks
    const plankItems = bot.inventory.items().filter((item) => item.name === "oak_planks");
    const plankCount = plankItems.reduce((sum, item) => sum + item.count, 0);
    const sticksNeeded = 3 - stickCount;
    const planksNeeded = Math.ceil(sticksNeeded / 4); // 1 plank → 4 sticks in 2x2

    if (plankCount < planksNeeded) {
      throw new Error(`Not enough planks to craft sticks: have ${plankCount}, need ${planksNeeded}`);
    }

    await craftItem(bot, "stick", planksNeeded * 4);
  }

  // Let craftItem validate materials (no manual redstone check)
  await craftItem(bot, "redstone_torch", 3);
  bot.chat("Crafted 3 redstone torches");
}

