async function craftRedstoneBlock(bot) {
    // The function crafts a redstone block using 9 redstone items and a crafting table. First, it checks if a redstone block is already present in the inventory, returning early if so. Then it verifies sufficient redstone (at least 9 units) and a crafting table (at least 1). If a crafting table is available, it attempts to place it in a safe, adjacent position around the bot. Once the crafting table is placed, it waits briefly and then crafts one redstone block. Finally, it confirms the successful crafting by checking the inventory for the newly created redstone block.
}

nodes.code:
async function craftRedstoneBlock(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Check if we already have a redstone_block
  const currentRedstoneBlock = bot.inventory.items().find(item => item.name === 'redstone_block');
  if (currentRedstoneBlock && currentRedstoneBlock.count >= 1) {
    bot.chat("Already have a redstone block in inventory.");
    return;
  }

  // Check if we have enough redstone (need 9)
  const redstoneItems = bot.inventory.items().filter(item => item.name === 'redstone');
  const totalRedstone = redstoneItems.reduce((sum, item) => sum + item.count, 0);
  if (totalRedstone < 9) {
    bot.chat(`Not enough redstone! Have ${totalRedstone}, need 9.`);
    return;
  }

  // Check if we already have a crafting table in inventory
  const craftingTableItems = bot.inventory.items().filter(item => item.name === 'crafting_table');
  const craftingTableCount = craftingTableItems.reduce((sum, item) => sum + item.count, 0);

  if (craftingTableCount < 1) {
    bot.chat("No crafting table in inventory! Cannot craft redstone block.");
    return;
  }

  // Place crafting table
  try {
    // Find a safe position to place the crafting table near the bot
    const botPos = bot.entity.position;
    // Try positions around the bot
    const positionsToTry = [
      new Vec3(Math.floor(botPos.x) + 1, Math.floor(botPos.y), Math.floor(botPos.z)),
      new Vec3(Math.floor(botPos.x) - 1, Math.floor(botPos.y), Math.floor(botPos.z)),
      new Vec3(Math.floor(botPos.x), Math.floor(botPos.y), Math.floor(botPos.z) + 1),
      new Vec3(Math.floor(botPos.x), Math.floor(botPos.y), Math.floor(botPos.z) - 1)
    ];

    let placed = false;
    for (const pos of positionsToTry) {
      // Check if position is air
      const blockAtPos = bot.blockAt(pos);
      if (blockAtPos && blockAtPos.name === 'air') {
        try {
          await placeItem(bot, 'crafting_table', pos);
          placed = true;
          bot.chat("Crafting table placed successfully.");
          break;
        } catch (e) {
          bot.chat(`Failed to place crafting table at ${pos}: ${e.message}`);
        }
      }
    }

    if (!placed) {
      bot.chat("Could not find a safe spot to place crafting table!");
      return;
    }

    // Wait a moment for block to be registered
    await new Promise(resolve => setTimeout(resolve, 500));

    // Now craft the redstone_block
    try {
      await craftItem(bot, 'redstone_block', 1);
      bot.chat("Crafted 1 redstone block!");

      // Verify we have the redstone_block
      const newRedstoneBlock = bot.inventory.items().find(item => item.name === 'redstone_block');
      if (newRedstoneBlock && newRedstoneBlock.count >= 1) {
        bot.chat(`Successfully crafted redstone block! Now have ${newRedstoneBlock.count}.`);
      } else {
        bot.chat("Crafting completed but redstone_block not found in inventory.");
      }
    } catch (craftError) {
      bot.chat(`Crafting error: ${craftError.message}`);
    }
  } catch (placeError) {
    bot.chat(`Placement error: ${placeError.message}`);
  }
}

