async function craftDiamondSword(bot) {
    // The function crafts a diamond sword by first ensuring at least one diamond is available, then moving the bot to the surface (y ≥ 60), crafting a crafting table if missing using existing logs, placing the crafting table two blocks ahead of the bot, and finally using the placed table to craft the diamond sword, verifying success and reporting the result.
}

nodes.code:
async function craftDiamondSword(bot) {
  const mcData = require("minecraft-data")(bot.version);

  // First, ensure we have diamonds (handles mining or using existing)
  await ensureDiamonds(bot, 1);

  // Ensure bot ascends to surface (y>=60) before attempting wood/crafting
  await exploreUntil(bot, new Vec3(0, 1, 0), 120, () => bot.entity.position.y >= 60);

  // Ensure we have a crafting table: craft from logs if not in inventory
  const craftingTableInInv = bot.inventory.findInventoryItem(mcData.itemsByName["crafting_table"].id);
  if (!craftingTableInInv) {
    // Use existing logs to craft planks then table in inventory (no need for furnace or surface)
    await craftOakCraftingTable(bot);
  }

  // Place the crafting table (now guaranteed to be in inventory)
  const position = bot.entity.position.offset(2, 0, 0).floored();
  await placeItem(bot, "crafting_table", position);

  // Craft the diamond sword using placed crafting table
  await craftItem(bot, "diamond_sword", 1);

  // Verify result
  const sword = bot.inventory.findInventoryItem(mcData.itemsByName["diamond_sword"].id);
  if (!sword) {
    throw new Error("Failed to craft diamond_sword");
  }
  bot.chat(`Crafted diamond_sword. Count: ${sword.count}`);
}

