async function craftJukebox(bot) {
    // The function crafts 1 jukebox by first ensuring a crafting table is placed nearby, then attempting to craft the jukebox and handling errors by diagnosing missing recipes or insufficient materials.
}

nodes.code:
async function craftJukebox(bot) {
  const mcData = require("minecraft-data")(bot.version);

  // Ensure crafting table is placed nearby by using the target skill
  await placeCraftingTable(bot);

  // Now craft 1 jukebox using the crafting table
  try {
    await craftItem(bot, 'jukebox', 1);
    bot.chat("Successfully crafted 1 jukebox!");
  } catch (e) {
    // Diagnose why crafting failed
    const recipeInfo = bot.checkRecipe('jukebox', 1, true);
    if (!recipeInfo.exists) {
      bot.chat(`No recipe for jukebox: ${recipeInfo.message}`);
    } else if (!recipeInfo.available) {
      bot.chat(`Insufficient materials: ${recipeInfo.message}`);
    } else {
      bot.chat(`Crafting error: ${e.message}`);
    }
    throw e;
  }
}

nodes.description:
async function craftHopper(bot) {
    // The function crafts a hopper by first ensuring a crafting table is available nearby, placing one if needed by trying two positions in front of or to the side of the bot. It then attempts to craft a hopper using `craftItem`, and if that fails, it checks for insufficient materials—specifically fewer than 5 iron ingots or no chest—and reports the issue before rethrowing the error.
}

nodes.code:
async function craftHopper(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Check if a crafting table block is already placed nearby (within 32 blocks)
  const craftingTableBlock = bot.findBlock({
    matching: mcData.blocksByName['crafting_table'].id,
    maxDistance: 32
  });

  let tableNeeded = true;
  if (craftingTableBlock) {
    tableNeeded = false;
    // Table already exists, no need to place
  }

  if (tableNeeded) {
    // Place a crafting table from inventory
    const pos = bot.entity.position.offset(0, 0, 1); // Place in front of bot
    try {
      await placeItem(bot, 'crafting_table', pos);
      // Wait a moment for block to place
      await new Promise(resolve => setTimeout(resolve, 500));
    } catch (e) {
      bot.chat("Failed to place crafting table: " + e.message);
      // Try alternative position
      const altPos = bot.entity.position.offset(1, 0, 0);
      try {
        await placeItem(bot, 'crafting_table', altPos);
      } catch (e2) {
        throw new Error("Could not place crafting table");
      }
    }
  }

  // Now craft the hopper
  try {
    await craftItem(bot, 'hopper', 1);
    bot.chat("Crafted 1 hopper");
  } catch (e) {
    // Check if we have enough materials
    const ironIngot = bot.inventory.items().find(i => i.name === 'iron_ingot');
    const chest = bot.inventory.items().find(i => i.name === 'chest');
    if (!ironIngot || ironIngot.count < 5) {
      bot.chat(`Not enough iron ingots: have ${ironIngot ? ironIngot.count : 0}, need 5`);
    }
    if (!chest) {
      bot.chat("No chest in inventory");
    }
    throw e;
  }
}

nodes.description:
async function mineCopperOre(bot) {
    // The function mines 4 copper ore blocks using a pickaxe (implicitly confirmed to be stone-tier or better, like an iron pickaxe). After mining, it checks the inventory to count the total copper ore items collected and compares this to the target of 4, reporting success or shortfall via chat.
}

nodes.code:
async function mineCopperOre(bot) {
  const mcData = require("minecraft-data")(bot.version);

  // Confirm we have a pickaxe that can mine copper_ore (Tier 1+: stone or better)
  // copper_ore requires stone_pickaxe or better (Tier 1+)
  // We already have iron_pickaxe equipped, which is sufficient

  // Mine 4 copper_ore blocks
  await mineBlock(bot, 'copper_ore', 4);

  // Verify we have enough copper_ore in inventory
  const copperOreItems = bot.inventory.items().filter(item => item.name === 'copper_ore');
  const totalCopperOre = copperOreItems.reduce((sum, item) => sum + item.count, 0);

  if (totalCopperOre >= 4) {
    bot.chat(`Successfully mined ${totalCopperOre} copper_ore.`);
  } else {
    bot.chat(`Only mined ${totalCopperOre} copper_ore, target was 4.`);
  }
}

nodes.description:
async function smeltRawCopper(bot) {
    // The function smelts 16 raw copper into copper ingots using a furnace and coal as fuel. First, it checks if a furnace is nearby; if not, it places one adjacent to the bot. Then, it smelts the specified quantity of raw copper using coal as fuel.
}

nodes.code:
async function smeltRawCopper(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Place furnace if not already placed nearby
  const furnaceBlock = bot.findBlock({
    matching: mcData.blocksByName['furnace'].id,
    maxDistance: 32
  });

  if (!furnaceBlock) {
    // Place furnace adjacent to the bot
    const targetPos = new Vec3(Math.floor(bot.position.x) + 1, Math.floor(bot.position.y), Math.floor(bot.position.z));
    await placeItem(bot, 'furnace', targetPos);
  }

  // Smelt 16 raw_copper using available fuel (coal)
  await smeltItem(bot, 'raw_copper', 'coal', 16);
  bot.chat("Successfully smelted 16 raw_copper into copper_ingot.");
}

nodes.description:
async function craftOakNoteBlock(bot) {
    // The function crafts a note block using a crafting table and required materials (8 oak planks and 1 redstone). First, it ensures a crafting table is placed nearby, placing one safely if missing. Then, it checks for sufficient oak logs to craft 8 planks and crafts them if needed. Next, it verifies that at least 8 oak planks and 1 redstone are available in inventory. After confirming materials, it attempts to craft 1 note block. Finally, it validates that the note block was successfully crafted and added to the inventory, throwing errors at any failure point.
}

nodes.code:
async function craftOakNoteBlock(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Step 1: Check if a crafting table is already present and usable
  let craftingTableBlock = bot.findBlock({
    matching: mcData.blocksByName["crafting_table"].id,
    maxDistance: 32,
  });

  // Step 2: If not, place it safely at a verified offset from the bot
  if (!craftingTableBlock) {
    const safeOffset = bot.entity.position.offset(0, 0, 1).floored();
    await placeItem(bot, "crafting_table", safeOffset);
    // Wait briefly for block update
    await bot.waitForTicks(10);
    // Re-verify placement
    craftingTableBlock = bot.findBlock({
      matching: mcData.blocksByName["crafting_table"].id,
      maxDistance: 32,
    });
    // If still not found, throw error immediately to avoid invalid 3x3 craft
    if (!craftingTableBlock) {
      throw new Error("Failed to place crafting table for note_block craft");
    }
  }

  // Step 3: Defer plank crafting until after table is confirmed — only craft what we need
  const oakLogItems = bot.inventory.items().filter((item) => item.name === "oak_log");
  const totalOakLog = oakLogItems.reduce((sum, item) => sum + item.count, 0);
  if (totalOakLog < 2) {
    throw new Error("Not enough oak_log to craft 8 planks.");
  }
  await craftItem(bot, "oak_planks", 8);
  bot.chat("Crafted 8 oak planks from oak_log.");

  // Step 4: Verify materials for note_block before crafting
  const planksItems = bot.inventory.items().filter((item) => item.name === "oak_planks");
  const totalPlanks = planksItems.reduce((sum, item) => sum + item.count, 0);
  const redstoneItems = bot.inventory.items().filter((item) => item.name === "redstone");
  const totalRedstone = redstoneItems.reduce((sum, item) => sum + item.count, 0);

  if (totalPlanks < 8 || totalRedstone < 1) {
    throw new Error("Insufficient materials for note_block (need 8 oak planks + 1 redstone).");
  }

  // Step 5: Craft the note_block and verify outcome
  try {
    await craftItem(bot, "note_block", 1);
  } catch (err) {
    throw new Error(`craftItem failed for note_block: ${err.message}`);
  }

  // Step 6: Verify the desired outcome — ensure note_block is in inventory
  const noteBlockItems = bot.inventory.items().filter((item) => item.name === "note_block");
  const totalNoteBlocks = noteBlockItems.reduce((sum, item) => sum + item.count, 0);
  if (totalNoteBlocks < 1) {
    throw new Error(
      "Failed to craft note_block despite materials and table — check crafting table placement or recipe",
    );
  }

  bot.chat("Crafted 1 note block.");
}

nodes.description:
async function craftCopperBlock(bot) {
    // The function crafts one copper block by first ensuring a crafting table is available nearby, placing one if necessary using a crafting table from the inventory, and then using the crafting table to craft the copper block.
}

nodes.code:
async function craftCopperBlock(bot) {
  const { Vec3 } = require("vec3");
  const mcData = require("minecraft-data")(bot.version);

  // Ensure a crafting table is available and placed nearby
  let craftingTablePos = null;
  const nearbyCraftingTable = bot.findBlock({
    matching: mcData.blocksByName['crafting_table'].id,
    maxDistance: 32
  });

  if (!nearbyCraftingTable) {
    // No crafting table nearby, place one
    const craftingTableItem = bot.inventory.findInventoryItem(mcData.itemsByName['crafting_table'].id);
    if (craftingTableItem) {
      // Find a suitable position to place the crafting table (adjacent to bot)
      const botPos = bot.entity.position;
      const positionsToCheck = [
        new Vec3(Math.round(botPos.x), Math.round(botPos.y), Math.round(botPos.z) - 1),
        new Vec3(Math.round(botPos.x), Math.round(botPos.y), Math.round(botPos.z) + 1),
        new Vec3(Math.round(botPos.x) - 1, Math.round(botPos.y), Math.round(botPos.z)),
        new Vec3(Math.round(botPos.x) + 1, Math.round(botPos.y), Math.round(botPos.z))
      ];

      for (const pos of positionsToCheck) {
        try {
          await placeItem(bot, 'crafting_table', pos);
          craftingTablePos = pos;
          bot.chat("Crafting table placed.");
          break;
        } catch (e) {
          // Try next position
        }
      }
    } else {
      throw new Error("No crafting table in inventory to place.");
    }
  }

  // Craft 1 copper_block
  await craftItem(bot, 'copper_block', 1);
  bot.chat("Crafted 1 copper_block.");
}

