    throw new Error("Failed to craft diamond boots");
  }
}

nodes.description:
async function ensureCoal(bot, count = 5) {
    // The function ensures the bot has at least a specified number of coal (default 5) by first scanning for coal ore blocks (prioritizing deepslate_coal_ore below Y=0 and both types between Y=0 and Y=20) and mining one if found nearby; if not, it explores horizontally in four directions, repeatedly scanning for eligible coal ore blocks while mining upon discovery and aborting exploration if no progress is made for 30 seconds.
}

nodes.code:
async function ensureCoal(bot, count = 5) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Helper: count total coal items in inventory
  function getCoalCount() {
    const items = bot.inventory.items();
    let total = 0;
    for (const item of items) {
      if (item.name === "coal") {
        total += item.count;
      }
    }
    return total;
  }

  // Helper: get IDs for coal ore variants
  const coalOreId = mcData.blocksByName["coal_ore"]?.id;
  const deepslateCoalOreId = mcData.blocksByName["deepslate_coal_ore"]?.id;

  if (coalOreId === undefined || deepslateCoalOreId === undefined) {
    throw new Error("Could not find coal ore block IDs in mcData");
  }

  // Try to get enough coal
  let attempts = 0;
  while (getCoalCount() < count && attempts < 5) {
    attempts++;

    // Y-aware scan priority: deepslate_coal_ore only when y <= 0, both when 0 < y <= 20
    let foundBlock = null;
    const currentY = bot.position.y;

    if (currentY <= 0) {
      // Deep underground: only deepslate_coal_ore is possible
      foundBlock = bot.findBlock({
        matching: [deepslateCoalOreId],
        maxDistance: 32,
      });
    } else if (currentY <= 20) {
      // Near surface: check deepslate first, then surface coal_ore
      foundBlock = bot.findBlock({
        matching: [deepslateCoalOreId, coalOreId],
        maxDistance: 32,
      });
    } else {
      // High altitude: only surface coal_ore is possible
      foundBlock = bot.findBlock({
        matching: [coalOreId],
        maxDistance: 32,
      });
    }

    let mined = false;
    if (foundBlock) {
      const block = bot.blockAt(foundBlock);
      // Null-check after bot.blockAt — skip if chunk not loaded or block unavailable
      if (!block) {
        // skip, chunk not loaded
        continue;
      }
      // Only mine if close in Y to avoid unreachable blocks
      if (Math.abs(block.position.y - bot.position.y) <= 5) {
        try {
          await mineBlock(bot, block.name, 1);
          mined = true;
        } catch (e) {
          // If mining fails (e.g., not reachable), we'll explore
        }
      }
    }

    if (!mined) {
      // Explore horizontally to find coal ore, reusing previous scan result via closure
      const directions = [new Vec3(1, 0, 0), new Vec3(-1, 0, 0), new Vec3(0, 0, 1), new Vec3(0, 0, -1)];
      let explored = false;
      for (const dir of directions) {
        const startBlock = foundBlock; // Capture for closure
        const startPos = bot.position.clone();
        let lastDiscoveryTime = Date.now();

        const result = await exploreUntil(bot, dir, 60, () => {
          // Reuse the Y-aware scan logic with single scan per callback invocation
          const scanY = bot.position.y;
          let targetMatching = [];
          if (scanY <= 0) {
            targetMatching = [deepslateCoalOreId];
          } else if (scanY <= 20) {
            targetMatching = [deepslateCoalOreId, coalOreId];
          } else {
            targetMatching = [coalOreId];
          }

          // Perform single scan per callback (avoid redundant scans)
          const nearby = bot.findBlock({
            matching: targetMatching,
            maxDistance: 32,
          });

          if (!nearby) {
            // Abort exploration if no discovery for 30s
            if (Date.now() - lastDiscoveryTime > 30000) {
              return "timeout";
            }
            return null;
          }

          const block = bot.blockAt(nearby);
          if (!block) {
            // Skip null blocks
            return null;
          }

          lastDiscoveryTime = Date.now();
          return block.name;
        });

        if (result && typeof result === "string" && result !== "timeout") {
          // Found a block name — attempt to mine one
          try {
            await mineBlock(bot, result, 1);
            mined = true;
            explored = true;
            break;
          } catch (e) {
            // Ignore and continue to next direction
          }
        }
        if (result === "timeout") {
          // Skip further directions if this one timed out (no progress)
          break;
        }
      }
    }
  }

  const finalCount = getCoalCount();
  if (finalCount >= count) {
    bot.chat(`Successfully ensured ${finalCount} coal.`);
  } else {
    bot.chat(`Only have ${finalCount} coal, needed ${count}.`);
  }
}

nodes.description:
async function ensureStone(bot, count = 3) {
    // The function ensures the bot has at least the specified number of stone blocks by mining cobblestone, smelting it in a nearby furnace (placing one if missing), and using available fuel (coal, charcoal, or other valid fuels). It first checks the current inventory for stone and skips if sufficient; otherwise, it mines enough cobblestone to meet the deficit. Then it smelts the cobblestone into stone, prioritizing coal and charcoal as fuel and falling back to crafting charcoal from oak logs if necessary. Smelting proceeds in batches based on fuel availability, and finally verifies and reports whether the required stone count was achieved.
}

nodes.code:
async function ensureStone(bot, count = 3) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Ensure furnace exists BEFORE proceeding (critical for smelting)
  const furnaceBlock = bot.findBlock({
    matching: mcData.blocksByName.furnace.id,
    maxDistance: 32,
  });

  if (!furnaceBlock) {
    bot.chat("No furnace nearby. Placing a furnace.");
    await placeItem(bot, "furnace", bot.entity.position.offset(2, 0, 0).floored());
  }

  // Cache inventory once to avoid redundant queries
  let inventoryItems = bot.inventory.items();

  // Check current stone and exit early if sufficient
  const currentStone = inventoryItems
    .filter((item) => item.name === "stone")
    .reduce((sum, item) => sum + item.count, 0);
  if (currentStone >= count) {
    bot.chat(`Already have ${currentStone} stone, need ${count}. Skipping.`);
    return;
  }

  const stoneNeeded = count - currentStone;
  bot.chat(`Need ${stoneNeeded} more stone. Starting cobblestone mining and smelting.`);

  // Mine cobblestone if needed
  const currentCobblestone = inventoryItems
    .filter((item) => item.name === "cobblestone")
    .reduce((sum, item) => sum + item.count, 0);
  const cobblestoneToMine = Math.max(0, stoneNeeded - currentCobblestone);

  if (cobblestoneToMine > 0) {
    bot.chat(`Mining ${cobblestoneToMine} cobblestone from nearby stone blocks.`);
    await mineBlock(bot, "stone", cobblestoneToMine);
  }

  // Refresh inventory and compute totals
  inventoryItems = bot.inventory.items();
  const cobblestoneAfterMine = inventoryItems
    .filter((item) => item.name === "cobblestone")
    .reduce((sum, item) => sum + item.count, 0);

  if (cobblestoneAfterMine <= 0) {
    bot.chat("No cobblestone to smelt after mining.");
    return;
  }

  // Prepare fuel with fallback chain: coal → charcoal → any valid fuel
  const coalItems = inventoryItems.filter((i) => i.name === "coal");
  const coalCount = coalItems.reduce((s, i) => s + i.count, 0);
  let charcoalCount = inventoryItems
    .filter((item) => item.name === "charcoal")
    .reduce((sum, item) => sum + item.count, 0);

  // Fallback: craft charcoal from logs if no charcoal or coal
  if (coalCount < Math.ceil(cobblestoneAfterMine / 8) && charcoalCount === 0) {
    bot.chat("Insufficient coal and charcoal. Crafting charcoal from oak logs.");
    try {
      // Ensure oak logs exist
      await ensureOakLogs(bot, 1);
      inventoryItems = bot.inventory.items();
      const logs = inventoryItems.filter((i) => i.name === "oak_log");
      const logCount = logs.reduce((s, i) => s + i.count, 0);
      if (logCount > 0) {
        bot.chat(`Found ${logCount} oak logs. Smelting to charcoal.`);
        // Use charcoal as fuel since coal is depleted
        await smeltItem(bot, "oak_log", "charcoal", logCount);
        inventoryItems = bot.inventory.items();
        charcoalCount = inventoryItems
          .filter((item) => item.name === "charcoal")
          .reduce((sum, item) => sum + item.count, 0);
      }
    } catch (err) {
      bot.chat(`Failed to craft charcoal: ${err.message}`);
    }
  }

  // Determine fuel options (coal first, then charcoal, then other valid fuels)
  const fuelOptions = [];
  if (coalCount > 0) fuelOptions.push({ name: "coal", count: coalCount });
  if (charcoalCount > 0) fuelOptions.push({ name: "charcoal", count: charcoalCount });

  // Fallback: any valid fuel from inventory
  const validFuels = mcData.itemsByType?.fuel || [];
  for (const fuelName of validFuels) {
    const fuelItem = inventoryItems.find((i) => i.name === fuelName);
    if (fuelItem && fuelItem.count > 0 && !fuelOptions.find((o) => o.name === fuelName)) {
      fuelOptions.push({ name: fuelName, count: fuelItem.count });
    }
  }

  if (fuelOptions.length === 0) {
    bot.chat("No fuel available for smelting. Cannot proceed.");
    return;
  }

  // Calculate max smeltable items (fuel-aware)
  let remainingCobblestone = cobblestoneAfterMine;
  let remainingToSmelt = stoneNeeded;
  for (const fuelOption of fuelOptions) {
    if (remainingToSmelt <= 0 || remainingCobblestone <= 0) break;

    // Determine how many fuel units needed for this batch
    const fuelUnitsNeeded = Math.ceil(Math.min(remainingCobblestone, remainingToSmelt) / 8);
    const fuelForThisBatch = Math.min(fuelUnitsNeeded, fuelOption.count);

    if (fuelForThisBatch <= 0) continue;

    const itemsToSmelt = fuelForThisBatch * 8;
    bot.chat(`Smelting up to ${itemsToSmelt} cobblestone with ${fuelOption.name}.`);

    try {
      await smeltItem(bot, "cobblestone", fuelOption.name, itemsToSmelt);
    } catch (e) {
      bot.chat(`Failed to smelt with ${fuelOption.name}: ${e.message}`);
      continue; // Continue with next fuel option
    }

    // Update tracking after each successful batch
    remainingCobblestone -= itemsToSmelt;
    remainingToSmelt -= itemsToSmelt;
  }

  // Final check
  inventoryItems = bot.inventory.items();
  const finalStone = inventoryItems.filter((item) => item.name === "stone").reduce((sum, item) => sum + item.count, 0);

  if (finalStone >= count) {
    bot.chat(`Successfully ensured ${finalStone} stone!`);
  } else {
    bot.chat(`Only have ${finalStone} stone, need ${count}.`);
  }
}

nodes.description:
async function placeChest(bot) {
    // The function attempts to place a chest from the bot’s inventory at a predefined target position (32, 13, 4), first verifying it is air and adjacent to a solid block. If the target isn’t suitable, it searches nearby candidate positions that are air and have a neighboring solid block. Once a valid position is identified, it places the chest using `placeItem`. If no chest is in inventory or placement fails, it reports an error; on success, it confirms placement.
}

nodes.code:
async function placeChest(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Check if chest is in inventory
  const chestItem = bot.inventory.findInventoryItem(mcData.itemsByName['chest'].id);
  if (!chestItem) {
    bot.chat("No chest in inventory to place.");
    return false;
  }

  // Target position: (32, 13, 4) — this is air and adjacent to solid block (31, 13, 4) [andesite]
  const targetPos = new Vec3(32, 13, 4);

  // Verify target position is air
  const targetBlock = bot.blockAt(targetPos);
  if (!targetBlock || targetBlock.name !== 'air') {
    bot.chat(`Target position ${targetPos} is not air (is ${targetBlock?.name || 'unknown'}), trying nearby alternatives.`);
    // Try adjacent positions that are air and have a solid neighbor
    const candidates = [
      new Vec3(33, 13, 4), // east of bot, check (34, 13, 4) is solid? Yes, andesite
      new Vec3(32, 13, 5), // south of bot, check (32, 13, 6) is solid? Yes, stone
      new Vec3(32, 13, 3), // north of bot, check (32, 13, 2) is solid? Yes, andesite
      new Vec3(32, 12, 4), // below bot (but may be occupied by bot)
      new Vec3(32, 14, 4), // above bot — (32, 14, 4) is marked air, but need solid neighbor
    ];

    for (const pos of candidates) {
      const block = bot.blockAt(pos);
      if (block && block.name === 'air') {
        // Check for adjacent solid block
        let hasSolidNeighbor = false;
        const directions = [
          new Vec3(1, 0, 0), new Vec3(-1, 0, 0),
          new Vec3(0, 1, 0), new Vec3(0, -1, 0),
          new Vec3(0, 0, 1), new Vec3(0, 0, -1)
        ];
        for (const dir of directions) {
          const neighbor = bot.blockAt(pos.offset(dir.x, dir.y, dir.z));
          if (neighbor && neighbor.name !== 'air' && neighbor.name !== 'water' && neighbor.name !== 'lava') {
            hasSolidNeighbor = true;
            break;
          }
        }
        if (hasSolidNeighbor) {
          targetPos.set(pos.x, pos.y, pos.z);
          break;
        }
      }
    }
  }

  bot.chat(`Placing chest at ${targetPos}`);
  try {
    await placeItem(bot, 'chest', targetPos);
    bot.chat("Chest placed successfully.");
    return true;
  } catch (err) {
    bot.chat(`Failed to place chest: ${err.message}`);
    return false;
  }
}

