async function craftPolishedDeepslate(bot) {
    // The function crafts 16 polished_deepslate blocks by first ensuring a crafting table is placed nearby, then verifying sufficient deepslate or cobbled_deepslate material is available (mining more if needed), and finally crafting the polished_deepslate using the crafting table.
}

nodes.code:
async function craftPolishedDeepslate(bot) {
  const mcData = require("minecraft-data")(bot.version);
  const { Vec3 } = require("vec3");

  // Phase 1: Ensure a crafting table is placed (required for 3x3 recipe)
  let craftingTableBlock = bot.findBlock({
    matching: mcData.blocksByName.crafting_table.id,
    maxDistance: 32,
  });

  if (!craftingTableBlock) {
    // Ensure we have planks and craft a crafting table first
    const planks = bot.inventory.items().filter((item) => item.name.includes("plank"));
    let totalPlanks = planks.reduce((sum, item) => sum + item.count, 0);

    if (totalPlanks < 4) {
      throw new Error("Not enough planks to craft a crafting table");
    }

    await craftItem(bot, "crafting_table", 1);

    // Place it near the bot
    const targetPos = bot.entity.position.offset(2, 0, 0).floored();
    const craftingTableItem = bot.inventory.findInventoryItem(mcData.itemsByName.crafting_table.id);
    if (!craftingTableItem) throw new Error("Crafting table item not in inventory after crafting");

    await placeItem(bot, "crafting_table", targetPos);
    craftingTableBlock = bot.findBlock({
      matching: mcData.blocksByName.crafting_table.id,
      maxDistance: 32,
    });
  }

  // Phase 2: Check if we already have enough polished_deepslate
  const polishedDeepslateItems = bot.inventory.items().filter((item) => item.name === "polished_deepslate");
  const currentCount = polishedDeepslateItems.reduce((sum, item) => sum + item.count, 0);
  if (currentCount >= 16) {
    return;
  }

  // Phase 3: Check if we have enough input material (deepslate or cobbled_deepslate)
  const deepslateItems = bot.inventory
    .items()
    .filter((item) => item.name === "deepslate" || item.name === "cobbled_deepslate");
  const materialCount = deepslateItems.reduce((sum, item) => sum + item.count, 0);

  if (materialCount < 16) {
    // Mine only what we need to reach 16 total input material
    const needed = 16 - materialCount;
    await mineBlock(bot, "deepslate", needed);

    // Update material count after mining (to catch cobbled_deepslate conversion)
    const updatedDeepslateItems = bot.inventory
      .items()
      .filter((item) => item.name === "deepslate" || item.name === "cobbled_deepslate");
    const updatedMaterialCount = updatedDeepslateItems.reduce((sum, item) => sum + item.count, 0);

    // Ensure we have enough to craft
    if (updatedMaterialCount < 16) {
      throw new Error(`Insufficient deepslate/cobbled_deepslate: only ${updatedMaterialCount} available after mining`);
    }
  }

  // Phase 4: Craft polished_deepslate (1:1 conversion using crafting table)
  await craftItem(bot, "polished_deepslate", 16);
}
